1. package worktree
2. 
3. import (
4. 	"bytes"
5. 	"errors"
6. 	"fmt"
7. 	"os"
8. 	"os/exec"
9. 	"path/filepath"
10. 	"strconv"
11. 	"strings"
12. 	"sync"
13. )
14. 
15. // indexLocks serializes the diff commands that write a worktree's git index
16. // (`git add -N .`) by worktree path, so the cockpit's per-tick churn numstat and
17. // the selected session's full diff cannot collide on the same
18. // .git/worktrees/<name>/index.lock. Distinct worktrees take distinct locks and
19. // still run concurrently; only same-worktree operations queue. The map grows by
20. // at most one entry per worktree seen in the process lifetime.
21. var (
22. 	indexLocksMu sync.Mutex
23. 	indexLocks   = map[string]*sync.Mutex{}
24. )
25. 
26. // indexLock returns the lock guarding the git index of the worktree at path,
27. // creating it on first use.
28. func indexLock(path string) *sync.Mutex {
29. 	indexLocksMu.Lock()
30. 	defer indexLocksMu.Unlock()
31. 	mu, ok := indexLocks[path]
32. 	if !ok {
33. 		mu = &sync.Mutex{}
34. 		indexLocks[path] = mu
35. 	}
36. 	return mu
37. }
38. 
39. // Manager performs git worktree operations against a single repository. The
40. // zero value is not usable; set RepoDir and prefer New for sane defaults.
41. type Manager struct {
42. 	// Git is the git executable to invoke. Empty means "git" on PATH.
43. 	Git string
44. 	// RepoDir is the repository the worktree commands run against (git -C).
45. 	RepoDir string
46. 	// Home is the resolved $WASA_HOME passed to the Layout.
47. 	Home string
48. 	// Workspace is the workspace identifier passed to the Layout.
49. 	Workspace string
50. 	// Layout computes worktree paths. Empty means Central.
51. 	Layout Layout
52. }
53. 
54. // New returns a Manager for repoDir using the central layout. home is the
55. // resolved $WASA_HOME and workspace is the workspace identifier whose worktrees
56. // this manager places.
57. func New(repoDir, home, workspace string) *Manager {
58. 	return &Manager{
59. 		Git:       "git",
60. 		RepoDir:   repoDir,
61. 		Home:      home,
62. 		Workspace: workspace,
63. 		Layout:    Central,
64. 	}
65. }
66. 
67. // Toplevel returns the absolute path of the root of the git working tree that
68. // contains dir, via `git -C dir rev-parse --show-toplevel`. It is the single
69. // path→repository resolver shared by the CLI and the cockpit, so a directory
70. // always maps to the same repository regardless of who asks. It errors when dir
71. // is not inside a git repository, does not exist, or git is unavailable, so a
72. // caller can treat any error as "not a repository".
73. func Toplevel(dir string) (string, error) {
74. 	cmd := exec.Command("git", "-C", dir, "rev-parse", "--show-toplevel")
75. 	out, err := cmd.Output()
76. 	if err != nil {
77. 		return "", fmt.Errorf("not a git repository: %s", dir)
78. 	}
79. 	return strings.TrimSpace(string(out)), nil
80. }
81. 
82. // Worktree is one entry from git worktree list.
83. type Worktree struct {
84. 	Path     string
85. 	Head     string
86. 	Branch   string
87. 	Bare     bool
88. 	Detached bool
89. }
90. 
91. // Path returns the worktree path for branch under the manager's layout. It is
92. // the single seam through which Add and Remove resolve paths.
93. func (m *Manager) Path(branch string) string {
94. 	layout := m.Layout
95. 	if layout == nil {
96. 		layout = Central
97. 	}
98. 	return layout(Params{
99. 		Home:      m.Home,
100. 		Workspace: m.Workspace,
101. 		RepoPath:  m.RepoDir,
102. 		Branch:    branch,
103. 	})
104. }
105. 
106. // Add creates a worktree for branch at its computed path, creating the branch
107. // from the current HEAD when it does not already exist, and returns the path.
108. func (m *Manager) Add(branch string) (string, error) {
109. 	if branch == "" {
110. 		return "", errors.New("branch must not be empty")
111. 	}
112. 
113. 	path := m.Path(branch)
114. 	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
115. 		return "", fmt.Errorf("create worktree parent: %w", err)
116. 	}
117. 
118. 	args := []string{"worktree", "add"}
119. 	if m.branchExists(branch) {
120. 		args = append(args, path, branch)
121. 	} else {
122. 		args = append(args, "-b", branch, path)
123. 	}
124. 
125. 	if _, err := m.git(args...); err != nil {
126. 		return "", err
127. 	}
128. 	return path, nil
129. }
130. 
131. // List returns the worktrees registered for the repository.
132. func (m *Manager) List() ([]Worktree, error) {
133. 	out, err := m.git("worktree", "list", "--porcelain")
134. 	if err != nil {
135. 		return nil, err
136. 	}
137. 	return parseList(out), nil
138. }
139. 
140. // Remove removes the worktree identified by target. An absolute target is used
141. // as the worktree path verbatim; any other target is treated as a branch name
142. // and its path is computed via the manager's layout. Routing on filepath.IsAbs
143. // rather than os.Stat means an absolute path whose directory has already been
144. // deleted is never re-sanitized into a bogus branch segment. When force is false
145. // a worktree with uncommitted or untracked changes blocks the removal and git's
146. // error is surfaced; force passes --force so the dirty worktree is removed and
147. // its changes discarded. Removing an already-deleted worktree is a successful
148. // no-op: git's failure is swallowed and stale metadata pruned, so a teardown
149. // whose worktree vanished from disk still completes.
150. func (m *Manager) Remove(target string, force bool) error {
151. 	if target == "" {
152. 		return errors.New("target must not be empty")
153. 	}
154. 
155. 	path := target
156. 	if !filepath.IsAbs(target) {
157. 		path = m.Path(target)
158. 	}
159. 
160. 	args := []string{"worktree", "remove"}
161. 	if force {
162. 		args = append(args, "--force")
163. 	}
164. 	if _, err := m.git(append(args, path)...); err != nil {
165. 		if _, statErr := os.Stat(path); os.IsNotExist(statErr) {
166. 			_, _ = m.git("worktree", "prune") // already gone; drop stale metadata
167. 			return nil
168. 		}
169. 		return err
170. 	}
171. 	return nil
172. }
173. 
174. // Branches lists the repository's local branch names, most-recently-committed
175. // first, so a picker can present the branches a session is most likely to want.
176. // A repository with no commits yet has no branches and returns an empty slice.
177. func (m *Manager) Branches() ([]string, error) {
178. 	out, err := m.git(
179. 		"for-each-ref",
180. 		"--sort=-committerdate",
181. 		"--format=%(refname:short)",
182. 		"refs/heads",
183. 	)
184. 	if err != nil {
185. 		return nil, err
186. 	}
187. 	var names []string
188. 	for line := range strings.SplitSeq(string(out), "\n") {
189. 		if line = strings.TrimSpace(line); line != "" {
190. 			names = append(names, line)
191. 		}
192. 	}
193. 	return names, nil
194. }
195. 
196. // HeadSHA returns the full object name of the repository's current HEAD — the
197. // commit a worktree added now branches from. It is captured at session creation
198. // and stored so the worktree can later be diffed against it. It errors in a
199. // repository with no commits yet.
200. func (m *Manager) HeadSHA() (string, error) {
201. 	out, err := m.git("rev-parse", "HEAD")
202. 	if err != nil {
203. 		return "", err
204. 	}
205. 	return strings.TrimSpace(string(out)), nil
206. }
207. 
208. // DiffResult is a worktree's diff against its base commit: the unified diff text
209. // and the total added and removed line counts for the cockpit's summary line.
210. type DiffResult struct {
211. 	Text    string
212. 	Added   int
213. 	Removed int
214. }
215. 
216. // Diff returns the diff of the worktree at worktreePath against baseCommit, the
217. // commit the worktree branched from. It first runs `git add -N .` inside the
218. // worktree so untracked files appear in the diff as additions, then captures the
219. // unified diff and, separately, the numstat totals for the summary. The commands
220. // run inside the worktree rather than the main repository, so they see the
221. // session's working changes.
222. func (m *Manager) Diff(worktreePath, baseCommit string) (DiffResult, error) {
223. 	if worktreePath == "" || baseCommit == "" {
224. 		return DiffResult{}, errors.New(
225. 			"worktree path and base commit required",
226. 		)
227. 	}
228. 
229. 	lock := indexLock(worktreePath)
230. 	lock.Lock()
231. 	defer lock.Unlock()
232. 
233. 	if _, err := m.gitAt(worktreePath, "add", "-N", "."); err != nil {
234. 		return DiffResult{}, err
235. 	}
236. 	text, err := m.gitAt(worktreePath, "--no-pager", "diff", baseCommit)
237. 	if err != nil {
238. 		return DiffResult{}, err
239. 	}
240. 	stat, err := m.gitAt(
241. 		worktreePath, "--no-pager", "diff", "--numstat", baseCommit,
242. 	)
243. 	if err != nil {
244. 		return DiffResult{}, err
245. 	}
246. 
247. 	added, removed := parseNumstat(stat)
248. 	return DiffResult{Text: string(text), Added: added, Removed: removed}, nil
249. }
250. 
251. // DiffNumstat returns only the added and removed line totals of the worktree at
252. // worktreePath against baseCommit, without the full content diff. Like Diff it
253. // first runs `git add -N .` so newly created untracked files are counted, then
254. // sums `git diff --numstat <baseCommit>`. It is the cheap per-tick churn stat
255. // the cockpit computes for every worktree session row, where the full Diff is
256. // reserved for the one selected session. A clean worktree and a binary-only
257. // change both return 0, 0 (binary files report "-" in both columns and are
258. // skipped by parseNumstat).
259. func (m *Manager) DiffNumstat(
260. 	worktreePath, baseCommit string,
261. ) (added, removed int, err error) {
262. 	if worktreePath == "" || baseCommit == "" {
263. 		return 0, 0, errors.New("worktree path and base commit required")
264. 	}
265. 
266. 	lock := indexLock(worktreePath)
267. 	lock.Lock()
268. 	defer lock.Unlock()
269. 
270. 	if _, err := m.gitAt(worktreePath, "add", "-N", "."); err != nil {
271. 		return 0, 0, err
272. 	}
273. 	stat, err := m.gitAt(
274. 		worktreePath, "--no-pager", "diff", "--numstat", baseCommit,
275. 	)
276. 	if err != nil {
277. 		return 0, 0, err
278. 	}
279. 
280. 	added, removed = parseNumstat(stat)
281. 	return added, removed, nil
282. }
283. 
284. // parseNumstat sums the added and removed columns of `git diff --numstat`
285. // output. Each line is "added\tremoved\tpath"; binary files report "-" in both
286. // columns, which is skipped.
287. func parseNumstat(out []byte) (added, removed int) {
288. 	for line := range strings.SplitSeq(string(out), "\n") {
289. 		fields := strings.Fields(line)
290. 		if len(fields) < 2 {
291. 			continue
292. 		}
293. 		if a, err := strconv.Atoi(fields[0]); err == nil {
294. 			added += a
295. 		}
296. 		if r, err := strconv.Atoi(fields[1]); err == nil {
297. 			removed += r
298. 		}
299. 	}
300. 	return added, removed
301. }
302. 
303. // DeleteBranch deletes the local branch. When force is false git refuses to
304. // delete a branch whose commits are not merged into its upstream or HEAD (git
305. // branch -d); force deletes it regardless (git branch -D), discarding any
306. // unmerged work. The finish lifecycle force-deletes because wasa never merges,
307. // so a session's branch is routinely unmerged at teardown.
308. func (m *Manager) DeleteBranch(branch string, force bool) error {
309. 	if branch == "" {
310. 		return errors.New("branch must not be empty")
311. 	}
312. 
313. 	flag := "-d"
314. 	if force {
315. 		flag = "-D"
316. 	}
317. 	_, err := m.git("branch", flag, branch)
318. 	return err
319. }
320. 
321. // BranchExists reports whether branch exists locally in the repository. Resume
322. // uses it to fail before creating anything when a recorded branch is gone,
323. // rather than letting Add recreate the branch from scratch.
324. func (m *Manager) BranchExists(branch string) bool {
325. 	return m.branchExists(branch)
326. }
327. 
328. func (m *Manager) branchExists(branch string) bool {
329. 	cmd := exec.Command(
330. 		m.bin(),
331. 		"-C", m.RepoDir,
332. 		"rev-parse", "--verify", "--quiet",
333. 		"refs/heads/"+branch,
334. 	)
335. 	return cmd.Run() == nil
336. }
337. 
338. func (m *Manager) git(args ...string) ([]byte, error) {
339. 	return m.gitAt(m.RepoDir, args...)
340. }
341. 
342. // gitAt runs git with its working directory set to dir (git -C dir). The
343. // repository commands use RepoDir; the diff commands run inside the worktree,
344. // which is a different directory, so the two cannot share a fixed -C.
345. func (m *Manager) gitAt(dir string, args ...string) ([]byte, error) {
346. 	full := append([]string{"-C", dir}, args...)
347. 	cmd := exec.Command(m.bin(), full...)
348. 
349. 	var stdout, stderr bytes.Buffer
350. 	cmd.Stdout = &stdout
351. 	cmd.Stderr = &stderr
352. 
353. 	if err := cmd.Run(); err != nil {
354. 		msg := strings.TrimSpace(stderr.String())
355. 		if msg == "" {
356. 			return nil, fmt.Errorf("git %s: %w", strings.Join(args, " "), err)
357. 		}
358. 		return nil, fmt.Errorf(
359. 			"git %s: %w: %s",
360. 			strings.Join(args, " "),
361. 			err,
362. 			msg,
363. 		)
364. 	}
365. 	return stdout.Bytes(), nil
366. }
367. 
368. func (m *Manager) bin() string {
369. 	if m.Git == "" {
370. 		return "git"
371. 	}
372. 	return m.Git
373. }
374. 
375. func parseList(out []byte) []Worktree {
376. 	var (
377. 		result []Worktree
378. 		cur    Worktree
379. 		open   bool
380. 	)
381. 	flush := func() {
382. 		if open {
383. 			result = append(result, cur)
384. 			cur = Worktree{}
385. 			open = false
386. 		}
387. 	}
388. 
389. 	for line := range strings.SplitSeq(string(out), "\n") {
390. 		line = strings.TrimRight(line, "\r")
391. 		if line == "" {
392. 			flush()
393. 			continue
394. 		}
395. 		open = true
396. 
397. 		key, value, _ := strings.Cut(line, " ")
398. 		switch key {
399. 		case "worktree":
400. 			cur.Path = value
401. 		case "HEAD":
402. 			cur.Head = value
403. 		case "branch":
404. 			cur.Branch = strings.TrimPrefix(value, "refs/heads/")
405. 		case "bare":
406. 			cur.Bare = true
407. 		case "detached":
408. 			cur.Detached = true
409. 		}
410. 	}
411. 	flush()
412. 	return result
413. }
414.

